mapper.select:

where e.teacher_id = #{teacherId}
  and e.is_deleted = false

    and e.status = #{status}

order by e.priority desc, e.created_at desc
limit #{limit} offset #{offset}

select count(1)
from yx_escalation e
where e.teacher_id = #{teacherId}
  and e.is_deleted = false

    and e.status = #{status}


where e.student_id = #{studentId}
  and e.is_deleted = false

    and e.status = #{status}

order by e.created_at desc
limit #{limit} offset #{offset}

select count(1)
from yx_escalation e
where e.student_id = #{studentId}
  and e.is_deleted = false

    and e.status = #{status}
